import{_ as e,o as i,c as l,a7 as r}from"./chunks/framework.D8GRgv03.js";const p=JSON.parse('{"title":"发布日志","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),o={name:"changelog.md"};function s(t,a,n,d,h,c){return i(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="发布日志" tabindex="-1">发布日志 <a class="header-anchor" href="#发布日志" aria-label="Permalink to “发布日志”">​</a></h1><p>本文档记录 MusicFree 各版本的变更摘要、升级注意事项与破坏性变更。功能细节请参阅 <a href="/music-free-site/feature.html">功能特性</a> 与各功能模块文档。</p><hr><h2 id="阅读说明" tabindex="-1">阅读说明 <a class="header-anchor" href="#阅读说明" aria-label="Permalink to “阅读说明”">​</a></h2><h3 id="版本号规则" tabindex="-1">版本号规则 <a class="header-anchor" href="#版本号规则" aria-label="Permalink to “版本号规则”">​</a></h3><ul><li><strong>稳定版</strong>：<code>V1.x.y</code>（如 <code>V1.1.5</code>）</li><li><strong>预发布版</strong>：<code>v1.x.y-alpha.nn</code>（如 <code>v1.2.0-alpha.09</code>），功能可能仍在快速迭代，不建议直接用于生产环境</li></ul><h3 id="升级建议" tabindex="-1">升级建议 <a class="header-anchor" href="#升级建议" aria-label="Permalink to “升级建议”">​</a></h3><ol><li>升级前备份 <code>data/music.db</code> 与配置文件</li><li>关注各版本 <strong>升级说明</strong> 中的扫描、插件、配置变更</li><li>Alpha 版本之间可能包含数据库自动迁移；首次启动后观察日志是否正常</li><li>插件（尤其 <code>mf-plugin-gomusicdl</code>）版本与宿主需匹配，升级后建议在管理端确认插件已更新</li></ol><p>Docker 升级示例：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ansgoo/music-free:latest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><hr><h2 id="未发布-main-分支-计划-v1-2-0-alpha-10" tabindex="-1">未发布（<code>main</code> 分支，计划 <code>v1.2.0-alpha.10</code>） <a class="header-anchor" href="#未发布-main-分支-计划-v1-2-0-alpha-10" aria-label="Permalink to “未发布（main 分支，计划 v1.2.0-alpha.10）”">​</a></h2><blockquote><p>相对上一标签 <code>v1.2.0-alpha.09</code> 的累积变更（截至 2026-05-24）。</p></blockquote><h2 id="v1-1-9" tabindex="-1">V1.1.9 <a class="header-anchor" href="#v1-1-9" aria-label="Permalink to “V1.1.9”">​</a></h2><h3 id="更新特性" tabindex="-1">更新特性 <a class="header-anchor" href="#更新特性" aria-label="Permalink to “更新特性”">​</a></h3><h4 id="音乐去重-三步向导" tabindex="-1">音乐去重：三步向导 <a class="header-anchor" href="#音乐去重-三步向导" aria-label="Permalink to “音乐去重：三步向导”">​</a></h4><p>管理后台 <strong>音乐管理 → 音乐去重</strong> 改为清晰的三步流程，降低误操作风险：</p><ol><li><strong>生成指纹</strong> —— 为缺失指纹的曲目批量补算 Chromaprint（已有指纹自动跳过）</li><li><strong>重复检测</strong> —— 按可配置阈值比对全库，输出重复组与相似度分数</li><li><strong>去重</strong> —— 组内手动勾选假删除，或 <strong>按规则批量清理</strong>（同专辑内保留无损 &gt; 码率 &gt; 时长；跨专辑重复默认全部保留）</li></ol><p><img src="https://cdn.jsdelivr.net/gh/ansgoo/music-free-site@main/docs/public/img/remove-repeat.webp" alt="音乐去重三步流程"></p><h4 id="媒体源扫描与指纹-更快、更稳" tabindex="-1">媒体源扫描与指纹：更快、更稳 <a class="header-anchor" href="#媒体源扫描与指纹-更快、更稳" aria-label="Permalink to “媒体源扫描与指纹：更快、更稳”">​</a></h4><ul><li><strong>扫描提速</strong>：并发 worker、目录 hash 增量跳过未变更路径；WebDAV 支持部分读取与单次 OpenStream 解析，减少远程 I/O</li><li><strong>指纹与扫描解耦</strong>：入库扫描不再强绑指纹计算；支持定时补指纹任务与管理端异步全库回填</li><li><strong>指纹引擎</strong>：内嵌 <code>chromaprint.wasm</code> + ffmpeg/ffprobe，<strong>不再依赖系统 <code>fpcalc</code></strong>；WASM 堆内存可配置上限，大文件 / WebDAV 特殊格式拉取与运行时错误恢复更稳健，大幅降低了docker镜像体积</li><li><strong>指纹调度</strong>：支持任务中断与互斥锁，避免多任务争抢资源</li></ul><h4 id="arm-docker-多架构镜像" tabindex="-1">ARM Docker 多架构镜像 <a class="header-anchor" href="#arm-docker-多架构镜像" aria-label="Permalink to “ARM Docker 多架构镜像”">​</a></h4><p>CI 构建并推送 <strong>amd64 + arm64</strong> 双架构镜像，标签与 <code>V1.1.8</code> 一致，ARM NAS / 单板机可直接使用官方镜像。</p><h4 id="飞牛-fnos-原生应用-fpk" tabindex="-1">飞牛 fnOS 原生应用（FPK） <a class="header-anchor" href="#飞牛-fnos-原生应用-fpk" aria-label="Permalink to “飞牛 fnOS 原生应用（FPK）”">​</a></h4><p>新增 <strong>飞牛应用中心</strong> 可安装的原生 <code>.fpk</code> 包（非 Docker 模板），支持桌面快捷方式启停与向导配置音乐库路径；Release 流水线同时产出 <strong>amd64 / arm64</strong> 安装包</p><h4 id="其他改进" tabindex="-1">其他改进 <a class="header-anchor" href="#其他改进" aria-label="Permalink to “其他改进”">​</a></h4><ul><li><strong>WebDAV 媒体源</strong>：在开启「允许回写音乐源文件标签」时，清洗 / 刮削 / 元数据编辑可写回远程标签（需 WebDAV PUT 权限）</li><li><strong>标签清洗</strong>：内置 <code>RULE-03</code> 扩展支持标题前导下划线序号（如 <code>_01.</code>）清理</li><li><strong>远程搜索 / 下载</strong>：插件选项展示插件图标，远程曲目列表增加加载骨架屏</li><li><strong>默认策略</strong>：新装默认关闭「回写音频源文件标签」，降低误改 NAS 原文件风险（可在 <strong>系统设置</strong> 中开启）</li></ul><hr><h3 id="升级说明" tabindex="-1">升级说明 <a class="header-anchor" href="#升级说明" aria-label="Permalink to “升级说明”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>建议操作</th></tr></thead><tbody><tr><td>自旧版升级且已开启 <code>fingerprint.enabled</code></td><td>进入 <strong>音乐去重</strong> 执行「生成指纹」，或对媒体源全量扫描一次</td></tr><tr><td>飞牛用户</td><td>可选用 Docker 镜像或从 Release 附件安装对应架构 FPK</td></tr></tbody></table><p>升级前请备份 <code>data/music.db</code></p><hr><h3 id="其他修复" tabindex="-1">其他修复 <a class="header-anchor" href="#其他修复" aria-label="Permalink to “其他修复”">​</a></h3><ul><li>优化指纹生成任务状态提示与进度展示（支持更细粒度进度）</li><li>修正部分管理端路由重定向与守卫逻辑</li><li>依赖与构建脚本小幅更新，提升稳定性</li></ul><h2 id="v1-1-7" tabindex="-1">V1.1.7 <a class="header-anchor" href="#v1-1-7" aria-label="Permalink to “V1.1.7”">​</a></h2><h3 id="新功能" tabindex="-1">新功能 <a class="header-anchor" href="#新功能" aria-label="Permalink to “新功能”">​</a></h3><h4 id="歌曲许愿" tabindex="-1">歌曲许愿 <a class="header-anchor" href="#歌曲许愿" aria-label="Permalink to “歌曲许愿”">​</a></h4><ul><li>用户可为<strong>尚未入库</strong>的曲目提交愿望（手动新建，或从外部歌单未匹配条目一键 / 批量许愿）</li><li>愿望状态：<code>pending</code>（待处理）、<code>fulfilled</code>（已实现）、<code>rejected</code>（已拒绝）</li><li>按归一化键 <code>norm_key</code>（作品名|艺术家|专辑）去重；管理员实现时同键下所有用户的待处理愿望批量闭环</li><li>管理员 <strong>愿望管理</strong>（<code>/admin/wish</code>）：远程搜索、下载入库、拒绝；复用远程音乐搜索能力</li><li>外部歌单详情展示当前用户的 <code>wishStatus</code>（<code>none</code> / <code>wished</code> / <code>fulfilled</code>）</li><li>说明文档：<a href="/music-free-site/wish.html">许愿</a></li></ul><h4 id="歌单增强" tabindex="-1">歌单增强 <a class="header-anchor" href="#歌单增强" aria-label="Permalink to “歌单增强”">​</a></h4><ul><li>公开歌单不可删除，返回明确错误提示</li><li>新增未匹配曲目<strong>重链</strong>（<code>RelinkUnmatchedPlaylistSongs</code>）：库内已有对应歌曲时自动绑定外部歌单行</li><li>前端歌单卡片与列表 UI 重构（<code>PlaylistCard</code> 组件）</li></ul><h4 id="歌曲清洗功能" tabindex="-1">歌曲清洗功能 <a class="header-anchor" href="#歌曲清洗功能" aria-label="Permalink to “歌曲清洗功能”">​</a></h4><p>歌曲文件的元数据存在各种各样的脏数据，元数据清洗功能在扫描入库的时候会按照特定规则对歌曲文本进行清洗</p><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to “修复”">​</a></h3><ol><li>修复了<code>--gap-sm</code>CSS 变量丢失导致部分样式异常</li><li>修复了暗黑模式下，message消息看不清的样式异常</li><li>修复特定情况下播放器播放会有重音的问题</li><li>重构了歌单列表视图</li></ol>`,44)])])}const k=e(o,[["render",s]]);export{p as __pageData,k as default};
